import{_ as i,o as e,c as l,a0 as o}from"./chunks/framework.CSGB4SNl.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"java/eight-legged essay/java-hot200-day09.md","filePath":"java/eight-legged essay/java-hot200-day09.md"}'),h={name:"java/eight-legged essay/java-hot200-day09.md"};function t(r,a,s,d,n,c){return e(),l("div",null,[...a[0]||(a[0]=[o('<h4 id="redis的hash是什么" tabindex="-1">redis的hash是什么 <a class="header-anchor" href="#redis的hash是什么" aria-label="Permalink to &quot;redis的hash是什么&quot;">​</a></h4><ol><li>就是一个键值对，适合用来存储多个字段及其值，比如key存user:101，值存整个对象数据，改单个字段不用整体覆盖这一点上比string灵活，数据量小的时候用紧凑列表，数据量大的时候用hashTable</li><li>为啥一开始用紧凑列表呢，因为hash表为了维持其较高的查找效率，通常会给每个hash桶分配指针这就导致了内存占用大，而紧凑列表就是存储在一块连续的内存上的，且不用维护指针，hash扩容的话就类似HashMap那样有个负载因子，到达时进行扩容，一般是两倍</li><li>hash扩容的过程就是先准备一个hash表二，然后触发扩容就把hash表1的数据渐进性得拷贝到二-因为redis单线程数据量大就容易阻塞，然后拷贝完就清理表1的数据，再建表3以备下次的rehash</li></ol><h4 id="用户输入网址到网页显示发生了什么" tabindex="-1">用户输入网址到网页显示发生了什么 <a class="header-anchor" href="#用户输入网址到网页显示发生了什么" aria-label="Permalink to &quot;用户输入网址到网页显示发生了什么&quot;">​</a></h4><ol><li></li></ol><h4 id="什么是java中的原子性、可见性、有序性" tabindex="-1">什么是java中的原子性、可见性、有序性 <a class="header-anchor" href="#什么是java中的原子性、可见性、有序性" aria-label="Permalink to &quot;什么是java中的原子性、可见性、有序性&quot;">​</a></h4><ol><li>java并发问题其实都可以归为这三类问题</li><li>原子性就是指一个任务要么全执行完要么不执行，中途不能被打断</li><li>可见性就是指一个线程修改了数据另外一个线程立马就能看到最新的数据</li><li>有序性就是指代码执行顺序和程序执行顺序一样，因为cpu可能会为了性能对指令进行重排</li></ol><h4 id="进程和线程有什么区别" tabindex="-1">进程和线程有什么区别 <a class="header-anchor" href="#进程和线程有什么区别" aria-label="Permalink to &quot;进程和线程有什么区别&quot;">​</a></h4><ol><li>进程是资源调度的最小单位，线程是cpu调度的最小单位</li><li>每个进程都有自己的数据段、堆栈等，进程之间是相互独立的，线程是属于进程的，可以共享进程的内存空间数据段等，但是每个线程之间都有自己的栈，寄存器</li><li>进程切进程上下文切换成本高，线程之间切换相对低，但是线程之间影响大，一个线程出问题其它也会受到影响，进程间比较隔离不会有什么影响</li><li>线程间通信的话要注意同步问题</li></ol><h4 id="几种io模型" tabindex="-1">几种io模型 <a class="header-anchor" href="#几种io模型" aria-label="Permalink to &quot;几种io模型&quot;">​</a></h4><ol><li>同步阻塞io，就是read之后一直干等，中间会经历很多步骤效率较低</li><li>非同步阻塞io，read之后没数据就报错误，不用一直等，去轮询是否有结果</li><li>多路复用io，有线程去监听上万个连接，谁的数据到了就通知连接谁</li><li>信号驱动io，内核数据好了主动发个信号过来，听着好但是同一个tcp下信号对应7种事件根本没法分清对应事件，基本没什么人用</li><li>异步io，内核数据拷贝到用户空间后再回调通知，其它情况下都是自由的</li></ol>',10)])])}const p=i(h,[["render",t]]);export{u as __pageData,p as default};
